//! Closed plan-to-namespace inputs for one ActiveReblit publication attempt.
//!
//! This layer borrows the canonical paths, generated bytes, and sealed asset
//! descriptors already retained by the lifetime-bound BLS publication plan.
//! It performs no filesystem I/O, descriptor duplication, reopening, payload
//! copy, topology discovery, or mutation. XXH3 values remain non-cryptographic
//! checksums used for path naming and destination classification.

use std::{marker::PhantomData, rc::Rc, time::Instant};

use super::{
    active_reblit_bls_renderer::{
        BoundActiveReblitBlsPublication, BoundActiveReblitBlsPublicationPlan,
    },
    active_reblit_publication_plan::{
        ActiveReblitBootDestinationLayout, ActiveReblitBootDestinationRoot,
        MAX_ACTIVE_REBLIT_BOOT_PUBLICATIONS,
    },
};
use crate::linux_fs::descriptor_boot_namespace::{
    BootNamespaceRequest, RetainedBootNamespaceExpectedSource,
};

#[path = "active_reblit_boot_namespace_inputs/error.rs"]
mod error;

pub(in crate::client) use error::ActiveReblitBootNamespaceInputError;

const MAX_BOOT_NAMESPACE_INPUT_PATH_BYTES: usize = 8 * 1024 * 1024;
const MAX_BOOT_NAMESPACE_INPUT_LOGICAL_BYTES: u64 = 10 * 1024 * 1024 * 1024;
const MAX_BOOT_NAMESPACE_INPUT_GENERATED_BYTES: usize = 16 * 1024 * 1024;
const MAX_BOOT_NAMESPACE_INPUT_GENERATED_FILE_BYTES: usize = 1024 * 1024;
const MAX_BOOT_NAMESPACE_INPUT_WORK: usize = 2 * MAX_ACTIVE_REBLIT_BOOT_PUBLICATIONS;

const BOOT_NAMESPACE_INPUT_POLICY: BootNamespaceInputPolicy = BootNamespaceInputPolicy {
    max_publications: MAX_ACTIVE_REBLIT_BOOT_PUBLICATIONS,
    max_path_bytes: MAX_BOOT_NAMESPACE_INPUT_PATH_BYTES,
    max_logical_bytes: MAX_BOOT_NAMESPACE_INPUT_LOGICAL_BYTES,
    max_generated_bytes: MAX_BOOT_NAMESPACE_INPUT_GENERATED_BYTES,
    max_generated_file_bytes: MAX_BOOT_NAMESPACE_INPUT_GENERATED_FILE_BYTES,
    max_work: MAX_BOOT_NAMESPACE_INPUT_WORK,
};

/// Lifetime-bound namespace inputs split by the collision layout retained by
/// the prepared publication plan. The value is deliberately non-`Clone`.
pub(in crate::client) enum BoundActiveReblitBootNamespaceInputs<'plan> {
    BootAliasesEsp {
        shared: BoundActiveReblitBootNamespaceDomain<'plan>,
    },
    DistinctXbootldr {
        esp: BoundActiveReblitBootNamespaceDomain<'plan>,
        xbootldr: BoundActiveReblitBootNamespaceDomain<'plan>,
    },
}

/// One collision domain in original global plan order.
///
/// Requests and expected sources are positionally paired. Original indices
/// remain scalar evidence for joining later assessment results without
/// detaching any path, byte slice, or descriptor from this owner.
pub(in crate::client) struct BoundActiveReblitBootNamespaceDomain<'plan> {
    requests: Box<[BootNamespaceRequest<'plan>]>,
    expected_sources: Box<[RetainedBootNamespaceExpectedSource<'plan>]>,
    plan_indices: Box<[usize]>,
    _same_thread: PhantomData<Rc<()>>,
}

impl<'plan> BoundActiveReblitBootNamespaceDomain<'plan> {
    pub(in crate::client) fn requests(&self) -> &[BootNamespaceRequest<'plan>] {
        &self.requests
    }

    pub(in crate::client) fn expected_sources(&self) -> &[RetainedBootNamespaceExpectedSource<'plan>] {
        &self.expected_sources
    }

    pub(in crate::client) fn plan_indices(&self) -> &[usize] {
        &self.plan_indices
    }
}

#[derive(Clone, Copy)]
struct BootNamespaceInputPolicy {
    max_publications: usize,
    max_path_bytes: usize,
    max_logical_bytes: u64,
    max_generated_bytes: usize,
    max_generated_file_bytes: usize,
    max_work: usize,
}

struct BindingBudget<'clock, Clock> {
    policy: BootNamespaceInputPolicy,
    deadline: Instant,
    work: usize,
    now: &'clock mut Clock,
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
struct BindingMetrics {
    publications: usize,
    esp_publications: usize,
    boot_publications: usize,
    path_bytes: usize,
    logical_bytes: u64,
    generated_bytes: usize,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum DestinationSlot {
    Shared,
    Esp,
    Xbootldr,
}

struct DomainBuilder<'plan> {
    name: &'static str,
    expected_count: usize,
    requests: Vec<BootNamespaceRequest<'plan>>,
    expected_sources: Vec<RetainedBootNamespaceExpectedSource<'plan>>,
    plan_indices: Vec<usize>,
}

enum DestinationBuilders<'plan> {
    BootAliasesEsp {
        shared: DomainBuilder<'plan>,
    },
    DistinctXbootldr {
        esp: DomainBuilder<'plan>,
        xbootldr: DomainBuilder<'plan>,
    },
}

impl<'input, 'topology_view, 'topology_authority, 'attempt, 'stone, 'roots>
    BoundActiveReblitBlsPublicationPlan<
        'input,
        'topology_view,
        'topology_authority,
        'attempt,
        'stone,
        'roots,
    >
{
    /// Borrow every planned output into the exact retained destination layout.
    ///
    /// The caller-owned deadline is inherited unchanged from the revalidated
    /// render attempt. Success is only immutable assessment input; it confers
    /// no destination or publication authority.
    pub(in crate::client) fn bind_boot_namespace_inputs<'plan>(
        &'plan self,
    ) -> Result<BoundActiveReblitBootNamespaceInputs<'plan>, ActiveReblitBootNamespaceInputError>
    where
        'input: 'plan,
    {
        let mut now = Instant::now;
        bind_with_policy_and_clocks(
            self,
            BOOT_NAMESPACE_INPUT_POLICY,
            &mut now,
            Instant::now,
        )
    }
}

fn bind_with_policy_and_clocks<
    'plan,
    'input: 'plan,
    'topology_view,
    'topology_authority,
    'attempt,
    'stone,
    'roots,
    Clock,
    TerminalClock,
>(
    plan: &'plan BoundActiveReblitBlsPublicationPlan<
        'input,
        'topology_view,
        'topology_authority,
        'attempt,
        'stone,
        'roots,
    >,
    policy: BootNamespaceInputPolicy,
    now: &mut Clock,
    terminal_now: TerminalClock,
) -> Result<BoundActiveReblitBootNamespaceInputs<'plan>, ActiveReblitBootNamespaceInputError>
where
    Clock: FnMut() -> Instant,
    TerminalClock: FnOnce() -> Instant,
{
    let deadline = plan.input_deadline();
    let mut budget = BindingBudget::new(policy, deadline, now)?;
    if !plan.collision_domains_still_match() {
        return Err(ActiveReblitBootNamespaceInputError::CollisionDomainDrift);
    }

    let layout = plan.destination_layout();
    let preflight = scan_plan(plan, &mut budget)?;
    if preflight.publications == 0 {
        return Err(ActiveReblitBootNamespaceInputError::EmptyPublicationPlan);
    }
    if preflight.publications != plan.publication_count() {
        return Err(ActiveReblitBootNamespaceInputError::PreparedPublicationCountMismatch);
    }
    if preflight.path_bytes != plan.publication_path_bytes() {
        return Err(ActiveReblitBootNamespaceInputError::PreparedPathByteMismatch);
    }
    if preflight.generated_bytes != plan.publication_generated_bytes() {
        return Err(ActiveReblitBootNamespaceInputError::PreparedGeneratedByteMismatch);
    }
    if preflight.logical_bytes != plan.logical_bytes() {
        return Err(ActiveReblitBootNamespaceInputError::PreparedLogicalByteMismatch);
    }
    budget.require_deadline("post-preflight")?;

    let mut builders = DestinationBuilders::allocate(layout, preflight, &mut budget)?;
    let rebound = bind_plan(plan, layout, &mut builders, &mut budget)?;
    if rebound != preflight {
        return Err(ActiveReblitBootNamespaceInputError::ImmutablePlanDrift);
    }
    let bound = builders.finish()?;
    if !plan.collision_domains_still_match() {
        return Err(ActiveReblitBootNamespaceInputError::CollisionDomainDrift);
    }
    budget.require_deadline_at("terminal binding", terminal_now())?;
    Ok(bound)
}

fn scan_plan<'plan, 'input: 'plan, 'topology_view, 'topology_authority, 'attempt, 'stone, 'roots, Clock>(
    plan: &'plan BoundActiveReblitBlsPublicationPlan<
        'input,
        'topology_view,
        'topology_authority,
        'attempt,
        'stone,
        'roots,
    >,
    budget: &mut BindingBudget<'_, Clock>,
) -> Result<BindingMetrics, ActiveReblitBootNamespaceInputError>
where
    Clock: FnMut() -> Instant,
{
    let declared = plan.outputs().len();
    budget.require_publication_count(declared)?;
    let mut metrics = BindingMetrics::default();
    for (plan_index, output) in plan.outputs().enumerate() {
        metrics.observe(&output, plan_index, budget)?;
    }
    Ok(metrics)
}

fn bind_plan<'plan, 'input: 'plan, 'topology_view, 'topology_authority, 'attempt, 'stone, 'roots, Clock>(
    plan: &'plan BoundActiveReblitBlsPublicationPlan<
        'input,
        'topology_view,
        'topology_authority,
        'attempt,
        'stone,
        'roots,
    >,
    layout: ActiveReblitBootDestinationLayout,
    builders: &mut DestinationBuilders<'plan>,
    budget: &mut BindingBudget<'_, Clock>,
) -> Result<BindingMetrics, ActiveReblitBootNamespaceInputError>
where
    Clock: FnMut() -> Instant,
{
    let mut metrics = BindingMetrics::default();
    for (plan_index, output) in plan.outputs().enumerate() {
        let relative_path = metrics.observe(&output, plan_index, budget)?;
        // The live namespace observer still classifies destinations by the
        // existing non-cryptographic XXH3 checksum plus exact length while
        // byte-comparing the streams. SHA-256 binds the retained source's exact
        // bytes here; cryptographic destination verification, signatures, and
        // ownership provenance remain separate publication prerequisites.
        let request = BootNamespaceRequest::new(
            relative_path,
            output.expected_length(),
            output.expected_digest(),
        );
        let expected = bind_expected_source(&output, plan_index, budget)?;
        builders.push(
            destination_slot(layout, output.root()),
            request,
            expected,
            plan_index,
        )?;
    }
    Ok(metrics)
}

fn bind_expected_source<'plan, 'asset: 'plan, Clock>(
    output: &BoundActiveReblitBlsPublication<'plan, 'asset>,
    plan_index: usize,
    budget: &mut BindingBudget<'_, Clock>,
) -> Result<RetainedBootNamespaceExpectedSource<'plan>, ActiveReblitBootNamespaceInputError>
where
    Clock: FnMut() -> Instant,
{
    let source = if let Some(bytes) = output.generated_bytes() {
        if u64::try_from(bytes.len()).ok() != Some(output.expected_length()) {
            return Err(ActiveReblitBootNamespaceInputError::GeneratedSourceLengthMismatch { plan_index });
        }
        if super::boot_content_identity::BootContentIdentity::hash(bytes) != output.expected_content_identity() {
            return Err(ActiveReblitBootNamespaceInputError::GeneratedSourceIdentityMismatch { plan_index });
        }
        RetainedBootNamespaceExpectedSource::generated(bytes)
    } else {
        let asset = output
            .sealed_asset()
            .map_err(|source| ActiveReblitBootNamespaceInputError::RetainedSourceCatalog { plan_index, source })?
            .ok_or(ActiveReblitBootNamespaceInputError::MissingSealedSource { plan_index })?;
        if asset.digest() != output.expected_digest()
            || asset.length() != output.expected_length()
            || asset.content_identity() != output.expected_content_identity()
        {
            return Err(ActiveReblitBootNamespaceInputError::SealedSourceIdentityMismatch { plan_index });
        }
        RetainedBootNamespaceExpectedSource::sealed_descriptor(asset.descriptor())
    };
    budget.require_deadline("publication source binding")?;
    Ok(source)
}

impl BindingMetrics {
    fn observe<'plan, 'asset: 'plan, Clock>(
        &mut self,
        output: &BoundActiveReblitBlsPublication<'plan, 'asset>,
        plan_index: usize,
        budget: &mut BindingBudget<'_, Clock>,
    ) -> Result<&'plan str, ActiveReblitBootNamespaceInputError>
    where
        Clock: FnMut() -> Instant,
    {
        budget.step()?;
        self.publications = self.publications.saturating_add(1);
        budget.require_publication_count(self.publications)?;
        match output.root() {
            ActiveReblitBootDestinationRoot::Esp => {
                self.esp_publications = self.esp_publications.saturating_add(1);
            }
            ActiveReblitBootDestinationRoot::Boot => {
                self.boot_publications = self.boot_publications.saturating_add(1);
            }
        }
        let relative_path = output
            .relative_path()
            .to_str()
            .ok_or(ActiveReblitBootNamespaceInputError::NonUtf8PlanPath { plan_index })?;
        self.path_bytes = self.path_bytes.saturating_add(relative_path.len());
        if self.path_bytes > budget.policy.max_path_bytes {
            return Err(ActiveReblitBootNamespaceInputError::PathByteLimit {
                limit: budget.policy.max_path_bytes,
                actual: self.path_bytes,
            });
        }
        self.logical_bytes = self.logical_bytes.saturating_add(output.expected_length());
        if self.logical_bytes > budget.policy.max_logical_bytes {
            return Err(ActiveReblitBootNamespaceInputError::LogicalByteLimit {
                limit: budget.policy.max_logical_bytes,
                actual: self.logical_bytes,
            });
        }
        if let Some(bytes) = output.generated_bytes() {
            if bytes.len() > budget.policy.max_generated_file_bytes {
                return Err(ActiveReblitBootNamespaceInputError::GeneratedFileByteLimit {
                    plan_index,
                    limit: budget.policy.max_generated_file_bytes,
                    actual: bytes.len(),
                });
            }
            if u64::try_from(bytes.len()).ok() != Some(output.expected_length()) {
                return Err(ActiveReblitBootNamespaceInputError::GeneratedSourceLengthMismatch { plan_index });
            }
            self.generated_bytes = self.generated_bytes.saturating_add(bytes.len());
            if self.generated_bytes > budget.policy.max_generated_bytes {
                return Err(ActiveReblitBootNamespaceInputError::GeneratedTotalByteLimit {
                    limit: budget.policy.max_generated_bytes,
                    actual: self.generated_bytes,
                });
            }
        }
        Ok(relative_path)
    }
}

impl<'clock, Clock> BindingBudget<'clock, Clock>
where
    Clock: FnMut() -> Instant,
{
    fn new(
        policy: BootNamespaceInputPolicy,
        deadline: Instant,
        now: &'clock mut Clock,
    ) -> Result<Self, ActiveReblitBootNamespaceInputError> {
        let mut budget = Self {
            policy,
            deadline,
            work: 0,
            now,
        };
        budget.require_deadline("binding entry")?;
        Ok(budget)
    }

    fn step(&mut self) -> Result<(), ActiveReblitBootNamespaceInputError> {
        self.require_deadline("publication scan")?;
        let actual = self.work.saturating_add(1);
        if actual > self.policy.max_work {
            return Err(ActiveReblitBootNamespaceInputError::WorkLimit {
                limit: self.policy.max_work,
                actual,
            });
        }
        self.work = actual;
        Ok(())
    }

    fn require_publication_count(&self, actual: usize) -> Result<(), ActiveReblitBootNamespaceInputError> {
        if actual > self.policy.max_publications {
            Err(ActiveReblitBootNamespaceInputError::PublicationCountLimit {
                limit: self.policy.max_publications,
                actual,
            })
        } else {
            Ok(())
        }
    }

    fn require_deadline(&mut self, checkpoint: &'static str) -> Result<(), ActiveReblitBootNamespaceInputError> {
        let now = (self.now)();
        self.require_deadline_at(checkpoint, now)
    }

    fn require_deadline_at(
        &self,
        checkpoint: &'static str,
        now: Instant,
    ) -> Result<(), ActiveReblitBootNamespaceInputError> {
        if now > self.deadline {
            Err(ActiveReblitBootNamespaceInputError::DeadlineExceeded { checkpoint })
        } else {
            Ok(())
        }
    }
}

impl<'plan> DestinationBuilders<'plan> {
    fn allocate<Clock>(
        layout: ActiveReblitBootDestinationLayout,
        metrics: BindingMetrics,
        budget: &mut BindingBudget<'_, Clock>,
    ) -> Result<Self, ActiveReblitBootNamespaceInputError>
    where
        Clock: FnMut() -> Instant,
    {
        match layout {
            ActiveReblitBootDestinationLayout::BootAliasesEsp => Ok(Self::BootAliasesEsp {
                shared: DomainBuilder::allocate("shared ESP/BOOT", metrics.publications, budget)?,
            }),
            ActiveReblitBootDestinationLayout::DistinctXbootldr => Ok(Self::DistinctXbootldr {
                esp: DomainBuilder::allocate("ESP", metrics.esp_publications, budget)?,
                xbootldr: DomainBuilder::allocate("XBOOTLDR", metrics.boot_publications, budget)?,
            }),
        }
    }

    fn push(
        &mut self,
        slot: DestinationSlot,
        request: BootNamespaceRequest<'plan>,
        expected: RetainedBootNamespaceExpectedSource<'plan>,
        plan_index: usize,
    ) -> Result<(), ActiveReblitBootNamespaceInputError> {
        match (self, slot) {
            (Self::BootAliasesEsp { shared }, DestinationSlot::Shared) => {
                shared.push(request, expected, plan_index)
            }
            (Self::DistinctXbootldr { esp, .. }, DestinationSlot::Esp) => {
                esp.push(request, expected, plan_index)
            }
            (Self::DistinctXbootldr { xbootldr, .. }, DestinationSlot::Xbootldr) => {
                xbootldr.push(request, expected, plan_index)
            }
            _ => unreachable!("destination layout and slot are derived from one retained value"),
        }
    }

    fn finish(
        self,
    ) -> Result<BoundActiveReblitBootNamespaceInputs<'plan>, ActiveReblitBootNamespaceInputError> {
        match self {
            Self::BootAliasesEsp { shared } => Ok(BoundActiveReblitBootNamespaceInputs::BootAliasesEsp {
                shared: shared.finish()?,
            }),
            Self::DistinctXbootldr { esp, xbootldr } => {
                Ok(BoundActiveReblitBootNamespaceInputs::DistinctXbootldr {
                    esp: esp.finish()?,
                    xbootldr: xbootldr.finish()?,
                })
            }
        }
    }
}

impl<'plan> DomainBuilder<'plan> {
    fn allocate<Clock>(
        name: &'static str,
        expected_count: usize,
        budget: &mut BindingBudget<'_, Clock>,
    ) -> Result<Self, ActiveReblitBootNamespaceInputError>
    where
        Clock: FnMut() -> Instant,
    {
        if expected_count == 0 {
            return Err(ActiveReblitBootNamespaceInputError::EmptyDestinationDomain { domain: name });
        }
        let mut requests = Vec::new();
        reserve_exact(&mut requests, expected_count, name, "requests", budget)?;
        let mut expected_sources = Vec::new();
        reserve_exact(
            &mut expected_sources,
            expected_count,
            name,
            "expected sources",
            budget,
        )?;
        let mut plan_indices = Vec::new();
        reserve_exact(
            &mut plan_indices,
            expected_count,
            name,
            "plan indices",
            budget,
        )?;
        Ok(Self {
            name,
            expected_count,
            requests,
            expected_sources,
            plan_indices,
        })
    }

    fn push(
        &mut self,
        request: BootNamespaceRequest<'plan>,
        expected: RetainedBootNamespaceExpectedSource<'plan>,
        plan_index: usize,
    ) -> Result<(), ActiveReblitBootNamespaceInputError> {
        let actual = self.requests.len();
        if actual >= self.expected_count
            || self.expected_sources.len() != actual
            || self.plan_indices.len() != actual
        {
            return Err(ActiveReblitBootNamespaceInputError::DomainLengthMismatch {
                domain: self.name,
                expected: self.expected_count,
                actual: actual.saturating_add(1),
            });
        }
        self.requests.push(request);
        self.expected_sources.push(expected);
        self.plan_indices.push(plan_index);
        Ok(())
    }

    fn finish(self) -> Result<BoundActiveReblitBootNamespaceDomain<'plan>, ActiveReblitBootNamespaceInputError> {
        let actual = self.requests.len();
        if actual != self.expected_count
            || self.expected_sources.len() != self.expected_count
            || self.plan_indices.len() != self.expected_count
        {
            return Err(ActiveReblitBootNamespaceInputError::DomainLengthMismatch {
                domain: self.name,
                expected: self.expected_count,
                actual,
            });
        }
        Ok(BoundActiveReblitBootNamespaceDomain {
            requests: self.requests.into_boxed_slice(),
            expected_sources: self.expected_sources.into_boxed_slice(),
            plan_indices: self.plan_indices.into_boxed_slice(),
            _same_thread: PhantomData,
        })
    }
}

fn reserve_exact<T, Clock>(
    values: &mut Vec<T>,
    count: usize,
    domain: &'static str,
    resource: &'static str,
    budget: &mut BindingBudget<'_, Clock>,
) -> Result<(), ActiveReblitBootNamespaceInputError>
where
    Clock: FnMut() -> Instant,
{
    budget.require_deadline("pre-allocation")?;
    values
        .try_reserve_exact(count)
        .map_err(|source| ActiveReblitBootNamespaceInputError::Allocation {
            domain,
            resource,
            source,
        })?;
    budget.require_deadline("post-allocation")
}

const fn destination_slot(
    layout: ActiveReblitBootDestinationLayout,
    root: ActiveReblitBootDestinationRoot,
) -> DestinationSlot {
    match (layout, root) {
        (ActiveReblitBootDestinationLayout::BootAliasesEsp, _) => DestinationSlot::Shared,
        (ActiveReblitBootDestinationLayout::DistinctXbootldr, ActiveReblitBootDestinationRoot::Esp) => {
            DestinationSlot::Esp
        }
        (ActiveReblitBootDestinationLayout::DistinctXbootldr, ActiveReblitBootDestinationRoot::Boot) => {
            DestinationSlot::Xbootldr
        }
    }
}

